#### 任务 2.3: 完善迭代历史页面

**实现迭代列表和详情**:

```vue
<!-- Iterations.vue -->
<template>
  <div class="iterations-page">
    <!-- 搜索和筛选 -->
    <el-card class="filter-bar">
      <el-row :gutter="20">
        <el-col :span="8">
          <el-input
            v-model="searchKeyword"
            placeholder="搜索需求描述..."
            clearable
            @input="handleSearch"
          >
            <template #prefix>
              <el-icon><Search /></el-icon>
            </template>
          </el-input>
        </el-col>
        <el-col :span="6">
          <el-select v-model="statusFilter" placeholder="状态筛选" clearable>
            <el-option label="全部" value="" />
            <el-option label="成功" value="success" />
            <el-option label="失败" value="failed" />
            <el-option label="运行中" value="running" />
          </el-select>
        </el-col>
      </el-row>
    </el-card>

    <!-- 迭代列表 -->
    <el-card>
      <el-table
        :data="filteredIterations"
        v-loading="loading"
        stripe
        @row-click="viewDetail"
      >
        <el-table-column prop="iterationNumber" label="#" width="80" />
        <el-table-column prop="requirement" label="需求" show-overflow-tooltip />
        <el-table-column prop="status" label="状态" width="100">
          <template #default="{ row }">
            <el-tag :type="getStatusType(row.status)">
              {{ getStatusText(row.status) }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="duration" label="耗时" width="120">
          <template #default="{ row }">
            {{ formatDuration(row.duration) }}
          </template>
        </el-table-column>
        <el-table-column prop="createdAt" label="创建时间" width="180">
          <template #default="{ row }">
            {{ formatDate(row.createdAt) }}
          </template>
        </el-table-column>
        <el-table-column label="操作" width="150" fixed="right">
          <template #default="{ row }">
            <el-button size="small" @click.stop="viewDetail(row)">
              详情
            </el-button>
            <el-button
              size="small"
              type="warning"
              @click.stop="rollback(row)"
              :disabled="row.status === 'running'"
            >
              回滚
            </el-button>
          </template>
        </el-table-column>
      </el-table>

      <!-- 分页 -->
      <el-pagination
        v-model:current-page="currentPage"
        v-model:page-size="pageSize"
        :total="total"
        :page-sizes="[10, 20, 50, 100]"
        layout="total, sizes, prev, pager, next"
        @current-change="loadIterations"
        @size-change="loadIterations"
      />
    </el-card>

    <!-- 详情弹窗 -->
    <IterationDetailDialog
      v-model="detailVisible"
      :iteration="selectedIteration"
    />
  </div>
</template>

<script setup lang="ts">
import { ref, computed, onMounted } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import { useIterationStore } from '@/stores/iteration'
import IterationDetailDialog from '@/components/IterationDetailDialog.vue'

const iterationStore = useIterationStore()
const loading = ref(false)
const searchKeyword = ref('')
const statusFilter = ref('')
const currentPage = ref(1)
const pageSize = ref(20)
const total = ref(0)
const detailVisible = ref(false)
const selectedIteration = ref(null)

// 过滤迭代
const filteredIterations = computed(() => {
  return iterationStore.iterations.filter(i => {
    if (searchKeyword.value && !i.requirement.includes(searchKeyword.value)) {
      return false
    }
    if (statusFilter.value && i.status !== statusFilter.value) {
      return false
    }
    return true
  })
})

// 加载迭代列表
async function loadIterations() {
  loading.value = true
  try {
    await iterationStore.fetchIterations({
      page: currentPage.value,
      pageSize: pageSize.value
    })
    total.value = iterationStore.total
  } finally {
    loading.value = false
  }
}

// 搜索
function handleSearch() {
  currentPage.value = 1
}

// 查看详情
function viewDetail(iteration: any) {
  selectedIteration.value = iteration
  detailVisible.value = true
}

// 回滚
async function rollback(iteration: any) {
  try {
    await ElMessageBox.confirm(
      `确定要回滚到迭代 #${iteration.iterationNumber} 吗？`,
      '确认回滚',
      { type: 'warning' }
    )

    await iterationStore.rollback(iteration.id)
    ElMessage.success('回滚成功')
    await loadIterations()
  } catch (error) {
    if (error !== 'cancel') {
      ElMessage.error('回滚失败')
    }
  }
}

function getStatusType(status: string) {
  const types: Record<string, any> = {
    success: 'success',
    failed: 'danger',
    running: 'warning'
  }
  return types[status] || 'info'
}

function getStatusText(status: string) {
  const texts: Record<string, string> = {
    success: '成功',
    failed: '失败',
    running: '运行中'
  }
  return texts[status] || status
}

function formatDuration(ms: number) {
  const seconds = Math.floor(ms / 1000)
  if (seconds < 60) return `${seconds}s`
  const minutes = Math.floor(seconds / 60)
  return `${minutes}m ${seconds % 60}s`
}

function formatDate(date: string) {
  return new Date(date).toLocaleString('zh-CN')
}

onMounted(() => {
  loadIterations()
})
</script>
```

